}

fn default_global_hotkey() -> String {
    "Alt+Space".to_string()
}

const fn default_settings_version() -> u32 {
    1
}

#[derive(
    Debug, Clone, Serialize, Deserialize, Default, Display, EnumString, EnumIter, PartialEq, Eq,
)]
#[strum(serialize_all = "lowercase")]
